return {
  json: {
    // Sources
    sources: [
      "https://feeds.arstechnica.com/arstechnica/index",
      "https://www.theverge.com/rss/index.xml",
      "https://venturebeat.com/category/ai/feed",
      "https://techcrunch.com/feed/",
      "https://dev.to/feed"
    ],
    interest_rules: [
      // AI
      "LLM", "GPT", "Claude", "Gemini", "Llama", "OpenAI", "Anthropic", "Generative AI", "RAG", "Inference", "AI Ethics",

      // Hardware
      "Nvidia", "AMD", "Intel", "GPU", "CPU", "CUDA", "Ryzen", "Xeon", "H100", "Blackwell", "TSMC", "Raspberry Pi", "DDR5",

      // Infrastructure & Network
      "Kubernetes", "Docker", "Terraform", "Linux", "Cisco", "Juniper", "Firewall", "Router", "Switch", "Datacenter", "AWS", "Azure",

      // Security
      "CVE", "Vulnerability", "Zero-day", "Exploit", "Ransomware", "Cybersecurity"
    ]
  }
}

const items = $input.all();

let htmlEmail = `
<div style="font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; max-width: 600px; margin: auto; color: #333333;">
  <div style="background-color: #2c3e50; padding: 25px; text-align: center; border-radius: 8px 8px 0 0;">
    <h1 style="color: #ffffff; margin: 0; font-size: 24px; font-weight: 300; letter-spacing: 1px;">Daily News Letter</h1>
    <p style="color: #bdc3c7; margin: 5px 0 0; font-size: 13px; text-transform: uppercase;">${new Date().toISOString().split('T')[0]}</p>
  </div>
  <div style="background-color: #ffffff; border: 1px solid #e0e0e0; border-top: none;">
`;

if (items.length > 0) {
    for (const item of items) {
        const title = item.json.title || "Header missing";

        let summary = item.json.text || item.json.response || item.json.summary || "<p>Summary not possible.</p>";

        const link = item.json.link || "#";

        htmlEmail += `
        <div style="padding: 25px; border-bottom: 1px solid #f0f0f0;">
            <h2 style="margin-top: 0; margin-bottom: 10px; font-size: 18px; line-height: 1.4;">
                <a href="${link}" style="text-decoration: none; color: #2c3e50; font-weight: 700;">${title}</a>
            </h2>

            <div style="font-size: 15px; line-height: 1.6; color: #555555; margin-bottom: 15px;">
                ${summary}
            </div>

            <a href="${link}" style="display: inline-block; font-size: 13px; font-weight: 600; color: #3498db; text-decoration: none;">
                Read full article &rarr;
            </a>
        </div>
        `;
    }
} else {
    htmlEmail += `<div style="padding: 40px; text-align: center; color: #7f8c8d;">No relevant articles found today.</div>`;
}

htmlEmail += `
    <div style="background-color: #f9f9f9; padding: 15px; text-align: center; border-radius: 0 0 8px 8px; font-size: 12px; color: #95a5a6;">
      Automatically generated by n8n
    </div>
  </div>
</div>
`;

return [{
    json: {
        subject: `News summary: ${new Date().toISOString().split('T')[0]}`,
        htmlBody: htmlEmail
    }
}];

// 1. Fetch your rules and convert them to lowercase for safety
// CHANGE THE NAME HERE if your config node is named something other than "Get News Sources and Interest Rules"
const rulesData = $('Get News Sources and Interest Rules').first().json;
const rules = (rulesData.interest_rules || []).map(r => r.toLowerCase());

// 2. Loop through each article and keep only those that match
return items.filter(item => {
  const categories = item.json.categories;

  // If the article lacks a category entirely, discard it
  if (!categories) return false;

  let textToSearch = "";

  // 3. Normalize the data: Turn EVERYTHING into a long text string regardless of its previous format
  if (Array.isArray(categories)) {
    textToSearch = categories.join(" ").toLowerCase();
  } else if (typeof categories === 'string') {
    textToSearch = categories.toLowerCase();
  } else {
    // If it's an object or other weird format, stringify it
    textToSearch = JSON.stringify(categories).toLowerCase();
  }

  // 4. THE MAGIC CHECK: Does any of the rules exist in the text?
  // .some() returns true as soon as it finds ONE match
  const hasMatch = rules.some(rule => textToSearch.includes(rule));

  return hasMatch;
});
